#include <bits/stdc++.h>
using namespace std;
int main(){
   int n, m;
   if(!(cin >> n >> m)) return 0;
   vector<vector<int>> matrix(n, vector<int>(m));
   for(int i = 0; i < n; i++) {
      for(int j = 0; j < m; j++) {
         cin >> matrix[i][j];
      }
   }
   vector<vector<int>> rotated_matrix(m, vector<int>(n));
   for(int i = 0; i < n; i++) {
      for(int j = 0; j < m; j++) {
         rotated_matrix[j][n - i - 1] = matrix[i][j];
      }
   }
   for(int i = 0; i < m; i++) {
      for(int j = 0; j < n; j++) {
         cout << rotated_matrix[i][j] << ' ';
      }
      cout << endl;
   }
   return 0;
}
